const webhook = $('When Executed by Another Workflow').first().json;
const body = webhook.body;
const meta = body.metadonnees || {};
const entite = body.entiteData || {};

const timestamp = Date.now();
const random = Math.random().toString(36).substring(2, 8);
const idEmail = 'EMAIL_' + body.entiteId + '_' + timestamp + '_' + random;

return [{
  json: {
    id_email: idEmail,
    id_prospect: body.entiteId,
    correlation_id: body.correlationId,
    sens: 'sortant',
    email_expediteur: 'contact@academiedebijouteriejoaillerie.fr',
    nom_expediteur: 'ABJ',
    email_destinataire: meta.destinataire || entite.email,
    objet: meta.objet || 'Information ABJ',
    contenu: meta.contenu || '',
    prospect_nom: entite.nom,
    prospect_prenom: entite.prenom
  }
}];

