const formateur = $input.first().json;
const webhook = $('When Executed by Another Workflow').first().json;
const body = webhook.body;
const meta = body.metadonnees || {};

const timestamp = Date.now();
const random = Math.random().toString(36).substring(2, 8);
const idEmail = 'EMAIL_DOC_' + formateur.id_formateur + '_' + timestamp + '_' + random;

return [{
  json: {
    id_email: idEmail,
    id_formateur: formateur.id_formateur,
    notification_id: parseInt(body.notificationId) || 0,
    sens: 'sortant',
    email_expediteur: 'contact@academiedebijouteriejoaillerie.fr',
    nom_expediteur: 'ABJ',
    email_destinataire: meta.destinataire || formateur.email,
    objet: 'Demande de document : ' + (meta.libelleDocument || 'Document'),
    contenu: meta.contenu || ('Bonjour ' + formateur.prenom + ',\n\nNous vous prions de bien vouloir nous transmettre le document suivant : ' + (meta.libelleDocument || 'document requis') + '.\n\nMotif : ' + (meta.motif || 'Document requis pour votre dossier') + '\n\nCordialement,\nL\'Acad\u00e9mie de Bijouterie Joaillerie'),
    code_type_document: meta.codeTypeDocument || '',
    libelle_document: meta.libelleDocument || '',
    motif: meta.motif || '',
    formateur_nom: formateur.nom,
    formateur_prenom: formateur.prenom
  }
}];

